/* Retourne le SVG outline pour une icône individuelle de contenu (fallback: emoji original si non mappé) */
function contentIconSVG(emoji, size = 30) {
  // Icône via fichier /icons/*.svg — référence <use> vers le sprite partagé (#icons-sprite),
  // au lieu d'inliner le path complet à chaque appel (gain mémoire/poids DOM majeur)
  if (emoji && emoji.startsWith('/icons/')) {
    const icon = PATH_ICONS[emoji];
    if (icon) return `<svg width="${size}" height="${size}" viewBox="${icon.vb}" style="flex-shrink:0;vertical-align:-3px;"><use href="#${icon.id}"/></svg>`;
    return null; // fichier non intégré : laisser l'appelant gérer le fallback
  }
  // Icône SVG anatomique (format __SVG__filename__) — référence <use> vers le sprite partagé
  if (emoji && emoji.startsWith('__SVG__')) {
    const filename = emoji.replace(/^__SVG__/, '').replace(/__$/, '');
    const icon = SVG_ICONS[filename];
    if (icon) return `<svg width="${size}" height="${size}" viewBox="${icon.vb}" style="flex-shrink:0;"><use href="#${icon.id}"/></svg>`;
  }
  // Fallback : emoji → SVG via EMOJI_SVG
  const inner = EMOJI_SVG[emoji];
  if (!inner) return null;
  return `<svg width="${size}" height="${size}" viewBox="0 0 48 48" fill="none" stroke="currentColor" stroke-width="1.6" stroke-linecap="round" stroke-linejoin="round" style="flex-shrink:0;">${inner}</svg>`;
}

/* Retourne le SVG outline pour une catégorie (ou un cercle vide si id inconnu, pour ne jamais planter visuellement) */
function categoryIconSVG(id, size = 16) {
  const inner = CATEGORY_ICONS[id] || '<circle cx="12" cy="12" r="8"/>';
  const hasOwnFill = inner.includes('fill="currentColor"') || inner.includes("fill='currentColor'");
  if (hasOwnFill) {
    // Icône "pleine" (style filled, copiée depuis un fichier source riche en 48x48) : ne pas forcer stroke/fill sur le conteneur
    return `<svg width="${size}" height="${size}" viewBox="0 0 48 48" style="flex-shrink:0;vertical-align:-3px;color:inherit;">${inner}</svg>`;
  }
  // Icône "ligne" dessinée à la main en 24x24
  return `<svg width="${size}" height="${size}" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.7" stroke-linecap="round" stroke-linejoin="round" style="flex-shrink:0;vertical-align:-3px;">${inner}</svg>`;
}

/* ── Bandeau hero partagé (Pathologie / MAD / Dermatologie) ──
   colors: { mid, dark, accent } — dégradé radial + couleur d'accent du <em>
   closeAttr: attribut onclick du bouton fermer (laisser vide pour le masquer)
   editAttr: attribut onclick du bouton modifier (laisser vide pour le masquer) */
function buildFicheHero({ icone = '', categorie = '', nom = '', description = '', colors = {}, closeAttr = '', editAttr = '', docsAttr = '' }) {
  const { mid = '#15402c', dark = '#0c2a1e', accent = '#d8b86a' } = colors;
  const titleParts = String(nom || '').split(' ');
  const lastWord = titleParts.pop();
  const titleHTML = titleParts.length
    ? `${esc(titleParts.join(' '))} <em>${esc(lastWord)}</em>`
    : `<em>${esc(lastWord || '')}</em>`;
  return `
    <div class="fiche-hero" ${closeAttr ? `onclick="${closeAttr}"` : ''} style="--hero-mid:${mid};--hero-dark:${dark};--hero-accent:${accent};">
      <svg class="fiche-hero__deco" width="56" height="56" viewBox="0 0 80 80" fill="none" stroke="${accent}" stroke-width="1.1"><path d="M40 70C40 45 25 30 10 25M40 70C40 50 50 38 64 32M40 70V20"/><circle cx="10" cy="25" r="3"/><circle cx="64" cy="32" r="3"/></svg>
      ${(editAttr || closeAttr || docsAttr) ? `<div class="fiche-hero__actions">
        ${docsAttr ? `<button class="fiche-hero__docs" onclick="event.stopPropagation();${docsAttr}" title="Documents">📎</button>` : ''}
        ${editAttr ? `<button class="fiche-hero__edit" onclick="event.stopPropagation();${editAttr}">✏️ Modifier</button>` : ''}
        ${closeAttr ? `<button class="fiche-hero__close" onclick="event.stopPropagation();${closeAttr}">✕</button>` : ''}
      </div>` : ''}
      ${categorie ? `<div class="fiche-hero__eyebrow">
        <span>${contentIconSVG(icone, 14) || icone}</span>
        <span class="fiche-hero__eyebrow-dot"></span>
        <span class="fiche-hero__eyebrow-cat">${esc(categorie)}</span>
      </div>` : ''}
      <h2 class="fiche-hero__title">${titleHTML}</h2>
      ${description ? `<p class="fiche-hero__desc">${esc(description)}</p>` : ''}
    </div>`;
}
